import{_ as a,o as t,c as o,ae as n}from"./chunks/framework.B6gjLfeO.js";const p=JSON.parse('{"title":"EU Hosted Data","description":"","frontmatter":{"title":"EU Hosted Data","slug":"eu-hosted-data-for-new-enterprise-customers"},"headers":[],"relativePath":"account-hub/eu-hosted-data-for-new-enterprise-customers.md","filePath":"account-hub/eu-hosted-data-for-new-enterprise-customers.md"}'),r={name:"account-hub/eu-hosted-data-for-new-enterprise-customers.md"};function i(s,e,d,c,l,h){return t(),o("div",null,[...e[0]||(e[0]=[n('<p>As part of Branch&#39;s initiative to expand our regional data ingestion and storage capabilities in the EU, you can now choose to process and store your Branch data at our new AWS-powered data center in Ireland.</p><h2 id="eu-hosted-data-features" tabindex="-1">EU Hosted Data Features <a class="header-anchor" href="#eu-hosted-data-features" aria-label="Permalink to &quot;EU Hosted Data Features&quot;">​</a></h2><p>When you opt for Branch&#39;s new EU Hosted Data option, you can expect that:</p><ol><li>Branch SDK and Journeys endpoints that you communicate with will be hosted in the EU.</li><li>Data received by Branch (including PII) will be stored in the EU.</li><li>Exports and queries related to log-level data will occur in the EU.</li></ol><h2 id="data-distribution" tabindex="-1">Data Distribution <a class="header-anchor" href="#data-distribution" aria-label="Permalink to &quot;Data Distribution&quot;">​</a></h2><p>Please note that data cannot be split between the NA and EU regions - all of the data associated with a single Branch App ID must flow to a single region.</p><p>Also, log-level data will first land in the NA region for processing before being transferred to the EU region for storage. The original data which landed in the NA region will be removed.</p><h2 id="aggregate-data-and-account-info" tabindex="-1">Aggregate Data and Account Info <a class="header-anchor" href="#aggregate-data-and-account-info" aria-label="Permalink to &quot;Aggregate Data and Account Info&quot;">​</a></h2><p>Aggregate data and account information/metadata will continue to remain stored in the NA region.</p><h2 id="access" tabindex="-1">Access <a class="header-anchor" href="#access" aria-label="Permalink to &quot;Access&quot;">​</a></h2><p>This new EU Data Center option is an add-on feature. Please <a href="https://www.branch.io/contact-sales/" target="_blank" rel="noreferrer">contact our sales team</a> to learn more.</p>',11)])])}const g=a(r,[["render",i]]);export{p as __pageData,g as default};
